  },
  {
    "description": "Control typography, spacing, color, the cascade, selectors, custom properties, and responsive sizing without fighting the browser.",
    "title": "CSS foundations"
  },
  {
    "description": "Build layouts with normal flow, flexbox, grid, positioning, and container-aware decisions that work across phones, tablets, and desktops.",
    "title": "Responsive layout systems"
  },
  {
    "description": "Run JavaScript in the browser, read and change DOM nodes, handle events, and update the interface from user actions.",
    "title": "JavaScript for interactive pages"
  },
  {
    "description": "Collect user input with accessible labels, validation, disabled states, error messages, and feedback that helps people recover.",
    "title": "Forms, validation, and feedback"
  },
  {
    "description": "Manage focus, keyboard paths, ARIA used only where needed, reduced motion, contrast, and screen reader-friendly updates.",
    "title": "Accessibility and inclusive interaction"
