  {
    "description": "Profile rendering, layout shifts, bundle size, network waterfalls, image loading, and Core Web Vitals before shipping changes.",
    "title": "Frontend performance"
  },
  {
    "description": "Take a feature from user need through layout, component design, states, accessibility checks, tests, build, and deployment handoff.",
    "title": "End-to-end frontend feature workflow"
