    COURSE_TITLE: Inteligência Artificial
    COURSE_DESCRIPTION: A inteligência artificial transforma dados, regras e modelos em sistemas capazes de apoiar decisões.
    CHAPTERS: [
  {
    "description": "Constrói o primeiro modelo mental de IA: dados, regras, atributos, rótulos, previsões, erros e decisões em sistemas que pessoas realmente usam.",
    "title": "Dados, regras e previsões"
  },
  {
    "description": "Acompanha a IA desde sistemas simbólicos e regras de especialistas até aprendizado de máquina, deep learning e modelos de fundação.",
    "title": "Evolução da inteligência artificial"
  },
  {
    "description": "Transforma um pedido real em problema de previsão, classificação, ranqueamento, geração, planejamento ou automação com medidas claras de sucesso.",
    "title": "Formulação de problemas de IA"
  },
  {
    "description": "Cobre coleta, limpeza, rotulagem, documentação e divisão de bases de dados, evitando vazamento, vieses escondidos e métricas fora da tarefa real.",
    "title": "Coleta e preparação de dados"
  },
  {
    "description": "Treina e compara regressão, classificação, clusterização, árvores e modelos ensemble com métricas ligadas ao custo dos erros.",
    "title": "Modelos clássicos de aprendizado de máquina"
  },
  {
    "description": "Usa redes neurais, backpropagation, otimização, GPUs e frameworks de deep learning para modelar imagens, texto, áudio e dados estruturados.",
    "title": "Redes neurais e deep learning"
  },
  {
    "description": "Trabalha atenção, transformers, embeddings, pré-treinamento, ajuste por instruções e limites dos grandes modelos de linguagem.",
    "title": "Transformers e grandes modelos de linguagem"
  },
  {
    "description": "Desenha prompts, saídas estruturadas, chamadas de ferramentas, versionamento e testes para deixar o comportamento da IA mais fácil de manter.",
    "title": "Prompting e design de aplicações de IA"
  },
  {
    "description": "Constrói geração aumentada por recuperação com ingestão de documentos, chunking, embeddings, busca vetorial, reranking, montagem de contexto e citações.",
    "title": "Geração aumentada por recuperação"
  },
  {
    "description": "Avalia IA com baselines, dados separados, revisão humana, juízes automáticos, red teaming, análise de alucinações e testes de regressão.",
    "title": "Avaliação de IA e análise de alucinações"
  },
  {
    "description": "Verifica justiça, privacidade, consentimento, explicabilidade, model cards, riscos de uso indevido e governança antes que sistemas de IA afetem pessoas.",
    "title": "IA responsável e governança"
  },
  {
    "description": "Implanta recursos de IA com serving de modelos, monitoramento, fallbacks, orçamento de latência, controle de custo, resposta a incidentes e revisão humana.",
    "title": "Operação e implantação de IA"
  },
  {
    "description": "Acompanha um recurso de IA da formulação do problema até checagem de dados, desenho de modelo ou prompt, avaliação, lançamento, monitoramento e iteração.",
    "title": "Fluxo completo de produto com IA"
  }
]
